-- =============================================================================
-- Luxe Hair Studio — mock data seed for bizmous* user
-- Run in Supabase SQL Editor (Dashboard → SQL Editor → New Query)
-- =============================================================================

DO $$
DECLARE
  v_uid     UUID;
  v_addr    TEXT := '2847 Cascade Rd SW, Atlanta, GA 30311';
BEGIN
  -- ── Find user ─────────────────────────────────────────────────────────────
  SELECT id INTO v_uid FROM auth.users WHERE email ILIKE 'bizmous%' LIMIT 1;
  IF v_uid IS NULL THEN
    RAISE EXCEPTION 'No auth.users row found with email starting with "bizmous"';
  END IF;
  RAISE NOTICE 'Seeding user %', v_uid;

